import asyncio
import json
import logging
import secrets
from collections import defaultdict
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any

import websockets
from websockets.server import WebSocketServerProtocol


logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(name)s: %(message)s",
)
logger = logging.getLogger("mmo-server")


@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str
    metadata: Dict[str, Any] = field(default_factory=dict)


@dataclass
class Player:
    player_id: str
    websocket: WebSocketServerProtocol
    inventory: Set[str] = field(default_factory=set)


class GameState:
    def __init__(self) -> None:
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.player_locks: Dict[str, asyncio.Lock] = defaultdict(asyncio.Lock)
        self.items_lock = asyncio.Lock()
        self.players_lock = asyncio.Lock()

    async def register_player(self, player_id: str, websocket: WebSocketServerProtocol) -> Player:
        async with self.players_lock:
            if player_id in self.players:
                old_player = self.players[player_id]
                try:
                    await old_player.websocket.close(code=4001, reason="Replaced by new session")
                except Exception:
                    pass
            player = Player(player_id=player_id, websocket=websocket)
            self.players[player_id] = player
            logger.info("Player connected: %s", player_id)
            return player

    async def unregister_player(self, player_id: str) -> None:
        async with self.players_lock:
            if player_id in self.players:
                del self.players[player_id]
                logger.info("Player disconnected: %s", player_id)

    async def create_item(self, owner_id: str, name: str, metadata: Optional[Dict[str, Any]] = None) -> Item:
        item_id = secrets.token_hex(8)
        item = Item(item_id=item_id, name=name, owner_id=owner_id, metadata=metadata or {})
        async with self.items_lock:
            self.items[item_id] = item
        async with self.player_locks[owner_id]:
            player = self.players.get(owner_id)
            if player:
                player.inventory.add(item_id)
        return item

    async def get_player_snapshot(self, player_id: str) -> Dict[str, Any]:
        async with self.player_locks[player_id]:
            player = self.players.get(player_id)
            if not player:
                return {"player_id": player_id, "inventory": []}
            inventory_ids = list(player.inventory)

        async with self.items_lock:
            inventory = []
            for item_id in inventory_ids:
                item = self.items.get(item_id)
                if item:
                    inventory.append(
                        {
                            "item_id": item.item_id,
                            "name": item.name,
                            "owner_id": item.owner_id,
                            "metadata": item.metadata,
                        }
                    )
        return {"player_id": player_id, "inventory": inventory}

    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str) -> Dict[str, Any]:
        if from_player_id == to_player_id:
            raise ValueError("Cannot transfer item to self")

        first_id, second_id = sorted([from_player_id, to_player_id])

        async with self.player_locks[first_id]:
            async with self.player_locks[second_id]:
                async with self.items_lock:
                    from_player = self.players.get(from_player_id)
                    to_player = self.players.get(to_player_id)

                    if not from_player:
                        raise ValueError("Source player not connected")
                    if not to_player:
                        raise ValueError("Target player not connected")

                    item = self.items.get(item_id)
                    if not item:
                        raise ValueError("Item does not exist")

                    if item.owner_id != from_player_id:
                        raise ValueError("Source player does not own item")

                    if item_id not in from_player.inventory:
                        raise ValueError("Item missing from source inventory")

                    from_player.inventory.remove(item_id)
                    to_player.inventory.add(item_id)
                    item.owner_id = to_player_id

                    logger.info(
                        "Transferred item %s from %s to %s",
                        item_id,
                        from_player_id,
                        to_player_id,
                    )

                    return {
                        "item_id": item.item_id,
                        "name": item.name,
                        "owner_id": item.owner_id,
                        "metadata": item.metadata,
                    }


state = GameState()


async def send_json(ws: WebSocketServerProtocol, payload: Dict[str, Any]) -> None:
    await ws.send(json.dumps(payload))


async def broadcast_to_players(player_ids: Set[str], payload: Dict[str, Any]) -> None:
    targets = []
    async with state.players_lock:
        for player_id in player_ids:
            player = state.players.get(player_id)
            if player:
                targets.append(player.websocket)

    if not targets:
        return

    message = json.dumps(payload)
    await asyncio.gather(*(ws.send(message) for ws in targets), return_exceptions=True)


async def handle_message(player: Player, message: str) -> None:
    try:
        data = json.loads(message)
    except json.JSONDecodeError:
        await send_json(player.websocket, {"type": "error", "error": "Invalid JSON"})
        return

    msg_type = data.get("type")

    if msg_type == "ping":
        await send_json(player.websocket, {"type": "pong"})
        return

    if msg_type == "inventory":
        snapshot = await state.get_player_snapshot(player.player_id)
        await send_json(player.websocket, {"type": "inventory", "data": snapshot})
        return

    if msg_type == "create_item":
        name = data.get("name")
        metadata = data.get("metadata", {})
        if not isinstance(name, str) or not name:
            await send_json(player.websocket, {"type": "error", "error": "Invalid item name"})
            return
        if not isinstance(metadata, dict):
            await send_json(player.websocket, {"type": "error", "error": "Invalid metadata"})
            return

        item = await state.create_item(player.player_id, name, metadata)
        await send_json(
            player.websocket,
            {
                "type": "item_created",
                "item": {
                    "item_id": item.item_id,
                    "name": item.name,
                    "owner_id": item.owner_id,
                    "metadata": item.metadata,
                },
            },
        )
        return

    if msg_type == "trade_item":
        to_player_id = data.get("to_player_id")
        item_id = data.get("item_id")

        if not isinstance(to_player_id, str) or not to_player_id:
            await send_json(player.websocket, {"type": "error", "error": "Invalid target player"})
            return
        if not isinstance(item_id, str) or not item_id:
            await send_json(player.websocket, {"type": "error", "error": "Invalid item id"})
            return

        try:
            item = await state.transfer_item(player.player_id, to_player_id, item_id)
        except ValueError as e:
            await send_json(player.websocket, {"type": "error", "error": str(e)})
            return

        payload = {
            "type": "trade_completed",
            "from_player_id": player.player_id,
            "to_player_id": to_player_id,
            "item": item,
        }
        await broadcast_to_players({player.player_id, to_player_id}, payload)
        return

    await send_json(player.websocket, {"type": "error", "error": "Unknown message type"})


async def connection_handler(websocket: WebSocketServerProtocol) -> None:
    player: Optional[Player] = None
    try:
        raw = await asyncio.wait_for(websocket.recv(), timeout=10)
        try:
            hello = json.loads(raw)
        except json.JSONDecodeError:
            await send_json(websocket, {"type": "error", "error": "Invalid JSON"})
            await websocket.close(code=4000, reason="Invalid JSON")
            return

        if hello.get("type") != "auth":
            await send_json(websocket, {"type": "error", "error": "First message must be auth"})
            await websocket.close(code=4002, reason="Auth required")
            return

        player_id = hello.get("player_id")
        if not isinstance(player_id, str) or not player_id:
            await send_json(websocket, {"type": "error", "error": "Invalid player_id"})
            await websocket.close(code=4003, reason="Invalid player_id")
            return

        player = await state.register_player(player_id, websocket)
        await send_json(websocket, {"type": "auth_ok", "player_id": player_id})

        snapshot = await state.get_player_snapshot(player_id)
        await send_json(websocket, {"type": "inventory", "data": snapshot})

        async for message in websocket:
            await handle_message(player, message)

    except asyncio.TimeoutError:
        try:
            await send_json(websocket, {"type": "error", "error": "Auth timeout"})
        except Exception:
            pass
        await websocket.close(code=4004, reason="Auth timeout")
    except websockets.ConnectionClosed:
        pass
    except Exception as e:
        logger.exception("Unhandled connection error: %s", e)
        try:
            await send_json(websocket, {"type": "error", "error": "Internal server error"})
        except Exception:
            pass
    finally:
        if player:
            await state.unregister_player(player.player_id)


